第八屆YTP國中組 2023&#x2F;7&#x2F;28記分板 題目題目 總分:100&#x2F;185 送分題helloworld30&#x2F;30 1.股市小達人(Stonks)0&#x2F;10 有n個季節，一開始Nathan用x元買入一張股票，接下來N個季節公司會將股價更新為ai，然後發股息，每張股票會收到[ai&#x2F;100]元，接下來Nathan會用它存下來的股息買盡量多的股票，再最後一季Nathan將所有股票賣出，問他賣出股票後拿到的錢+剩下的股息有沒有比買股票花的錢多。 我想我肯定誤會題目了，一開始想說很簡單給姐姐寫，她寫很久都寫不出來，結果我也找不出錯誤…!?好像是因為overflow😭😢😭 2.一起學日語(Learn Japenese)10&#x2F;10 輸入字串，5個case，再變化後輸出，詳細見題目⬆ 照他的方法直接寫就好了，所以我把這題給姊姊寫，想說給她點參與感，她寫很久，在她寫的時候我就先想其他題目。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long//#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int t; string s; cin&gt;&gt;t; for(int i=0; i&lt;t; i++) &#123; cin&gt;&gt;s; if(s.substr(s.size()-2,1)!=&quot;r&quot; || s.substr(s.size()-1,1)!=&quot;u&quot;) &#123; s=s.substr(0,s.size()-1)+&quot;imasu&quot;; &#125; else &#123; if(s.substr(s.size()-3,1)==&quot;u&quot; &amp;&amp; s.substr(s.size()-4,1)==&quot;s&quot;) &#123; s=s.substr(0,s.size()-4)+&quot;simasu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;u&quot; &amp;&amp; s.substr(s.size()-4,1)==&quot;k&quot;) &#123; s=s.substr(0,s.size()-4)+&quot;kimasu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;a&quot; || s.substr(s.size()-3,1)==&quot;u&quot; || s.substr(s.size()-3,1)==&quot;o&quot;) &#123; s=s.substr(0,s.size()-1)+&quot;imasu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;i&quot;) &#123; s=s.substr(0,s.size()-2)+&quot;masu&quot;; &#125; else if(s.substr(s.size()-3,1)==&quot;e&quot;) &#123; s=s.substr(0,s.size()-2)+&quot;masu&quot;; &#125; &#125; cout&lt;&lt;s&lt;&lt;&quot;
&quot;; &#125; return 0;&#125; 3.十一(Eleven)10&#x2F;10 輸出符合 1.位數加總為n2.沒有03.被11整除 最大的數沒有符合的數就輸出-1 一開始我看到這題就覺得一定很簡單，就如果n是偶數就輸出n個1，否則輸出-1，結果上傳後…0分…啊!…為啥錯了…這時姊姊告訴我奇偶位數和可能差11啊，我才想到11的倍數的定義…可能一開始太緊張了吧XD，最後找到規律：如果n是奇數，&lt;&#x3D;11的就是-1，&gt;11的就輸出913+(n-13)個1，然後就AC了。 12345678910111213141516171819202122232425262728293031323334353637383940#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int n; cin&gt;&gt;n; if(n%2==1) &#123; if(n&lt;=11) cout&lt;&lt;&quot;-1
&quot;; else &#123; int a=(n-11)/2,b=n-a; cout&lt;&lt;913; REP(i,n-13) cout&lt;&lt;1; cout&lt;&lt;&quot;
&quot;; &#125; &#125; else &#123; REP(i,n) cout&lt;&lt;&quot;1&quot;; cout&lt;&lt;&quot;
&quot;; &#125; return 0;&#125; 4.路燈(Street Light)15&#x2F;15 N*M的地圖，一個在(x,y)且亮度為p的路燈會帶給(r,c)的亮度max(0,p-max(|r-x|,|c-y|))每個格子的亮度為每個路燈帶給它的亮度取最大值輸入每個格子的亮度b[i][j]，輸出那些座標有路燈和它的亮度 一開始我的想法是從盤面上最大亮度到最小看，每一次檢查(i,j)如果它最終亮度&gt;目前它的亮度，就設一個路燈亮度b[i][j]，如果&#x3D;就跳過，如果&lt;就代表不合理，輸出-1 O((nm)^2^)會TLE。之後一段時間都沒什麼想法，所以我就先做第5題，再回來看突然發現每一格的周圍八格一定&gt;&#x3D;它的亮度-1，否則無解，可以簡單證明其他狀況有解(或靠第六感)，而我還發現他不需要最小化路燈的數量，在亮度為p的路燈周圍設亮度為p-1的路燈有設和沒設是一樣的，所以我就把所有會亮的地方都設了路燈，路燈亮度就是這格的最終亮度b[i][j] O(mn)我想現實生活中這樣設路燈是智障才會做的是…XXXXD(啊不是很有錢!!XD) 不過其實我忘記檢查斜線了(我只檢查周圍4格)，他可能測資比較弱所以還是AC了。 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859#include&lt;bits/stdc++.h&gt;using namespace std;#define ll long long#define int long long#define FOR(i,a,b) for(int i=a;i&lt;b;i++)#define REP(i,n) FOR(i,0,n)#define REP1(i,n) FOR(i,1,(n)+1)#define RREP(i,n) for(int i=(n)-1;i&gt;=0;i--)#define f first#define s second#define pb push_back#define ALL(x) x.begin(),x.end()#define SZ(x) (int)(x.size())#define SQ(x) (x)*(x)#define pii pair&lt;int,int&gt;#define Graph vector&lt;vector&lt;int&gt;&gt;#define IOS() cin.sync_with_stdio(0),cin.tie(0),cout.tie(0)const int inf=(1ll&lt;&lt;62);const int maxn=1e5+5;const int mod=1e9+9;signed main()&#123; IOS(); int n,m; cin&gt;&gt;n&gt;&gt;m; vector&lt;vector&lt;int&gt;&gt; a(n,vector&lt;int&gt;(m)); vector&lt;pair&lt;pii,int&gt;&gt; an; REP(i,n) &#123; REP(j,m) &#123; cin&gt;&gt;a[i][j]; if(a[i][j]&gt;0) an.pb(&#123;&#123;i+1,j+1&#125;,a[i][j]&#125;); &#125; &#125; bool ok=1; REP(i,n-1) &#123; REP(j,n) &#123; if(a[i][j]&lt;a[i+1][j]-1||a[i+1][j]&lt;a[i][j]-1) &#123; ok=0; break; &#125; &#125; &#125; REP(i,n) &#123; REP(j,n-1) &#123; if(a[i][j]&lt;a[i][j+1]-1||a[i][j+1]&lt;a[i][j]-1) &#123; ok=0; break; &#125; &#125; &#125; if(ok) &#123; cout&lt;&lt;an.size()&lt;&lt;&quot;
